<?php $pageTitle='الشركاء'; include __DIR__.'/includes/header.php'; $pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST' && adminTableExists($pdo,'partners')){$pdo->prepare('INSERT INTO partners (name,website,description_ar,description_en,status,sort_order) VALUES (?,?,?,?,?,?)')->execute([trim($_POST['name']),trim($_POST['website']),trim($_POST['description_ar']),trim($_POST['description_en']),$_POST['status']??'active',(int)($_POST['sort_order']??0)]);} $items=adminTableExists($pdo,'partners')?adminFetchAll($pdo,'SELECT * FROM partners ORDER BY sort_order,id DESC'):[];?>
<div class="container-fluid"><h1 class="h4">إدارة الموردين والشركاء</h1><form method="post" class="card card-body mb-3"><div class="row g-2"><div class="col"><input class="form-control" name="name" placeholder="اسم الشريك" required></div><div class="col"><input class="form-control" name="website" placeholder="الموقع"></div><div class="col"><button class="btn btn-primary">إضافة</button></div></div></form><table class="table table-sm table-bordered"><tr><th>#</th><th>الاسم</th><th>الموقع</th></tr><?php foreach($items as $i):?><tr><td><?php echo $i['id'];?></td><td><?php echo escape($i['name']);?></td><td><?php echo escape($i['website']);?></td></tr><?php endforeach;?></table></div>
